title('raw signal step response') %[output:326f06f0]
ylabel('position') %[output:326f06f0]
xlabel('time') %[output:326f06f0]
%[text] S and Z-domain TF :
num=[9.677e13,1.808e15];
den=[1,1.804e5,4.822e14,2.645e15,4.291e15];
G_s = tf(num,den) %[output:4bb45041]
G_z= c2d(G_s, Ts, 'zoh') %[output:3e84d245]
%[text] step responses :
v=150;  %(Volt step input gain);
h=60;   %(target positon)
[y,t] = step(v*G_z, t);
plot(t,y) %[output:24ab1d99]
hold on %[output:24ab1d99]
grid on %[output:24ab1d99]
ylabel('position') %[output:24ab1d99]
xlabel('time') %[output:24ab1d99]
hold off %[output:24ab1d99]
%[text]   transient behaviour before the controller :
stepinfo(v*G_z) %[output:7d289f8a]
%[text] \-------------------------------------------------------------------------------------------------------
%[text] PID tuner :
pidTuner(G_s,'pid');
%[text] tuned PID in both s and z domain :
% Auto tune PID
[C, info] = pidtune(G_s, 'PID');

% Display gains
Kp = C.Kp %[output:26eb9a6c]
Ki = C.Ki %[output:64a7cb8a]
Kd = C.Kd %[output:9d38174c]


PID_s=tf([Kd Kp Ki],[1 0]) %[output:28c3e25c]
PID_z=c2d(PID_s, Ts, 'tustin')  %[output:9ecf39b2]
%[text] ### ---------------------------------------------------------------------------------------------------------
%[text] ### Cascaded TF after PID in Z Domain :
cascaded_TF_z = series(G_z, PID_z) %[output:815c18a1]
%[text] ### Closed-loop transfer function in Z Domain :
closed_loop_TF_z = feedback(cascaded_TF_z, 1) %[output:638563d8]
%[text] ### Comparison between Transient Response before and after our designed PID  :
transient_response_before=stepinfo(v*G_z) %before %[output:923404ea]
transient_response_after=stepinfo(h*closed_loop_TF_z) %after %[output:08119b58]
%[text] Comparison between the step steady state error before and after our designed PID  :
%before
[y1, t1]=step(v*G_z);          
ss_error_before=abs(h - y1(end) ) %[output:02d2aca7]
%after
[y2, t2]=step(h*closed_loop_TF_z);          
ss_error_after=abs(h - y2(end)) %[output:05bf29ae]
%[text] ### Step response comparison :
[y1,t1]=step(v*G_z);
plot(t1,y1) %[output:956510be]
title('Step Response before'); %[output:956510be]
xlabel('t'); %[output:956510be]
ylabel('position') %[output:956510be]
grid on %[output:956510be]

[y2, t2]=step(h*closed_loop_TF_z);
plot(t2,y2) %[output:5817134b]
title('Step Response after'); %[output:5817134b]
xlabel('t'); %[output:5817134b]
ylabel('position') %[output:5817134b]
grid on %[output:5817134b]

%[text] ## Root Locus in Z-domain comparison (before and after inserting PID) :
figure; %[output:7c100e0e]
rlocus(G_z) %[output:7c100e0e]
hold on; %[output:7c100e0e]
rlocus(closed_loop_TF_z); %[output:7c100e0e]
legend('Brfore Without PID', 'After'); %[output:7c100e0e]
title('Root Locus Comparison'); %[output:7c100e0e]
hold off %[output:7c100e0e]
%[text] 
 isstable(G_z)    %before %[output:7a7c48f9]
isstable(closed_loop_TF_z)    %after %[output:6ea8af94]
